  ('judicial-f0899a01-moex-00059', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '公務員執行職務時，完全依照裁量基準作成裁罰處分，而不考慮個案之差異性，其處分是否違法？', '["合法，因符合平等原則", "違法，因為裁量怠惰", "合法，但不符個案適當性", "違法，因裁量基準未經法律授權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00060', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非屬行政程序法規定之一般法律原則？', '["明確性原則", "誠實信用原則", "平等原則", "預防原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00061', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於依法行政原則之敘述，下列何者錯誤？', '["法律優位原則係指行政行為必須有法律依據，故稱為積極之依法行政", "行政行為應受法律及一般法律原則之拘束，此法律有明文規定", "法律保留原則係指重要事項應以法律加以規範", "屬於執行法律之細節性、技術性次要事項，得由機關發布命令為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00062', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於不確定法律概念，下列敘述何者正確？', '["法條使用不確定法律概念，即係賦予該管行政機關相當程度之裁量餘地", "基於租稅法定主義，關於租稅債務之規定，禁止使用不確定法律概念", "基於法律保留原則，關於行政罰之構成要件的規定，禁止使用不確定法律概念", "行政機關適用不確定法律概念之行政處分，行政法院得審查其合法性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00063', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於政府採購招標與審標行為之法律性質，下列敘述何者正確？', '["招標與審標均為私經濟行為", "招標為私法行為，審標為行政處分", "招標與審標均屬公法性質", "招標為公法行為，審標為私法行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00064', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政法上法律關係之敘述，下列何者正確？', '["使用人與公有市場間使用攤位之法律關係，依實務見解為行政契約", "得藉由行政契約形成私法之法律關係", "地方自治團體不得為公權利主體，對國家主張給付請求權", "其當事人關係為行政機關與人民之間，不包含行政機關與公務人員之間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
